// Pull both per-page forall ensures into the proof context so z3 instantiates
// the page_mappings/page_io_mappings triggers for both post1_self_ and
// post2_self_; without this z3 only fires on whichever quantifier it sees
// first and leaves the other run un-linked.
assert forall|p: PagePtr|
    post1_self_.page_is_mapped(p) && p != target_ptr implies
        post1_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p) by {};
assert forall|p: PagePtr|
    post2_self_.page_is_mapped(p) && p != target_ptr implies
        post2_self_.page_mappings(p) =~= pre_self_.page_mappings(p)
        && post2_self_.page_io_mappings(p) =~= pre_self_.page_io_mappings(p) by {};

// Same for the page_is_mapped <==> pre forall.
assert forall|p: PagePtr|
    post1_self_.page_is_mapped(p) <==> pre_self_.page_is_mapped(p) by {};
assert forall|p: PagePtr|
    post2_self_.page_is_mapped(p) <==> pre_self_.page_is_mapped(p) by {};

// Same for the container_owned_pages forall.
assert forall|c: ContainerPtr|
    post1_self_.container_map_4k@.dom().contains(c) implies
        post1_self_.get_container_owned_pages(c)
            =~= pre_self_.get_container_owned_pages(c) by {};
assert forall|c: ContainerPtr|
    post2_self_.container_map_4k@.dom().contains(c) implies
        post2_self_.get_container_owned_pages(c)
            =~= pre_self_.get_container_owned_pages(c) by {};

// Set-level (ghost) equalities by transitivity through pre_self_.
// allocated_pages_*() / mapped_pages_*() are in-module, so they unfold to
// the underlying Ghost<Set<..>>@ values.
assert(post1_self_.allocated_pages_4k() =~= post2_self_.allocated_pages_4k());
assert(post1_self_.allocated_pages_2m() =~= post2_self_.allocated_pages_2m());
assert(post1_self_.allocated_pages_1g() =~= post2_self_.allocated_pages_1g());
assert(post1_self_.mapped_pages_4k()    =~= post2_self_.mapped_pages_4k());
assert(post1_self_.mapped_pages_2m()    =~= post2_self_.mapped_pages_2m());
assert(post1_self_.mapped_pages_1g()    =~= post2_self_.mapped_pages_1g());

// Lift those into the @-form that det_<f>_equal actually compares.
assert((post1_self_.allocated_pages_4k)@ =~= (post2_self_.allocated_pages_4k)@);
assert((post1_self_.allocated_pages_2m)@ =~= (post2_self_.allocated_pages_2m)@);
assert((post1_self_.allocated_pages_1g)@ =~= (post2_self_.allocated_pages_1g)@);
assert((post1_self_.mapped_pages_4k)@    =~= (post2_self_.mapped_pages_4k)@);
assert((post1_self_.mapped_pages_2m)@    =~= (post2_self_.mapped_pages_2m)@);
assert((post1_self_.mapped_pages_1g)@    =~= (post2_self_.mapped_pages_1g)@);

// free_pages_*() spec fns reduce to .free_pages_*@.to_set(); their set
// equality on both sides gives us the spec-fn equality between post1/post2.
assert(post1_self_.free_pages_4k() =~= post2_self_.free_pages_4k());
assert(post1_self_.free_pages_2m() =~= post2_self_.free_pages_2m());
assert(post1_self_.free_pages_1g() =~= post2_self_.free_pages_1g());

// Container-map domain equalities post1 vs post2 via the pre side.
assert(post1_self_.container_map_4k@.dom() =~= post2_self_.container_map_4k@.dom());
assert(post1_self_.container_map_2m@.dom() =~= post2_self_.container_map_2m@.dom());
assert(post1_self_.container_map_1g@.dom() =~= post2_self_.container_map_1g@.dom());

// For container_map_4k we additionally have pointwise value equality on the
// shared domain (via get_container_owned_pages(c) =~= pre's get_*).  Combine
// with the domain equality to lift to a full Map ext-equality.
assert forall|c: ContainerPtr|
    #![trigger post1_self_.container_map_4k@[c], post2_self_.container_map_4k@[c]]
    post1_self_.container_map_4k@.dom().contains(c) implies
        post1_self_.container_map_4k@[c] =~= post2_self_.container_map_4k@[c] by {
    // post1.get_container_owned_pages(c) =~= pre.get_*(c)
    // post2.get_container_owned_pages(c) =~= pre.get_*(c)
    // and in-module get_container_owned_pages(c) == container_map_4k@[c].
};
assert(post1_self_.container_map_4k@ =~= post2_self_.container_map_4k@);

// Per-page mappings/io_mappings agree on every non-target page, and the
// target page maps to the same insert(...) on both sides, so the underlying
// page_array entries match position-wise on every valid index.
assert forall|p: PagePtr|
    #![trigger post1_self_.page_mappings(p), post2_self_.page_mappings(p)]
    post1_self_.page_is_mapped(p) || pre_self_.page_is_mapped(p) implies
        post1_self_.page_mappings(p) =~= post2_self_.page_mappings(p)
        && post1_self_.page_io_mappings(p) =~= post2_self_.page_io_mappings(p) by {
    if p == target_ptr {
        // both equal pre.page_mappings(target_ptr).insert((pcid, va))
    } else {
        // both equal pre.page_mappings(p) by the per-page forall above
    }
};
